 1→import { motion } from "motion/react";
 2→import type { ChatTab } from "@rearden/types";
 3→import { useChat } from "@/contexts/ChatContext";
 4→import styles from "./ChatTabBar.module.scss";
 5→
 6→const TABS: { value: ChatTab; label: string }[] = [
 7→  { value: "all", label: "All" },
 8→  { value: "unread", label: "Unread" },
 9→  { value: "pinned", label: "Pinned" },
10→];
11→
12→export function ChatTabBar() {
13→  const { activeTab, setActiveTab } = useChat();
14→
15→  return (
16→    <div className={styles.tabs}>
17→      {TABS.map((tab) => (
18→        <button
19→          key={tab.value}
20→          className={`${styles.tab} ${activeTab === tab.value ? styles.active : ""}`}
21→          onClick={() => setActiveTab(tab.value)}
22→        >
23→          {tab.label}
24→          {activeTab === tab.value && (
25→            <motion.div
26→              layoutId="chatTabIndicator"
27→              className={styles.indicator}
28→              transition={{ type: "spring", stiffness: 400, damping: 30 }}
29→            />
30→          )}
31→        </button>
32→      ))}
33→    </div>
34→  );
35→}
