 1→import { useEffect } from "react";
 2→import { useParams } from "react-router-dom";
 3→import { AnimatePresence, motion } from "motion/react";
 4→import { useChat } from "@/contexts/ChatContext";
 5→import { ChatSidebar } from "./ChatSidebar";
 6→import { ChatConversation } from "./ChatConversation";
 7→import styles from "./Chat.module.scss";
 8→
 9→export function Chat() {
10→  const { conversationId } = useParams<{ conversationId?: string }>();
11→  const { activeConversationId, openConversation } = useChat();
12→
13→  // Open conversation from URL param
14→  useEffect(() => {
15→    if (conversationId && conversationId !== activeConversationId) {
16→      openConversation(conversationId);
17→    }
18→  }, [conversationId]); // eslint-disable-line react-hooks/exhaustive-deps
19→
20→  return (
21→    <div className={styles.chat}>
22→      {/* Desktop: both panels */}
23→      <div className={styles.sidebarDesktop}>
24→        <ChatSidebar />
25→      </div>
26→      <div className={styles.conversationDesktop}>
27→        <ChatConversation />
28→      </div>
29→
30→      {/* Mobile: single panel with transition */}
31→      <div className={styles.mobileContainer}>
32→        <AnimatePresence mode="wait">
33→          {activeConversationId ? (
34→            <motion.div
35→              key="conv"
36→              className={styles.mobilePanel}
37→              initial={{ x: "100%" }}
38→              animate={{ x: 0 }}
39→              exit={{ x: "100%" }}
40→              transition={{ type: "spring", stiffness: 400, damping: 35 }}
41→            >
42→              <ChatConversation />
43→            </motion.div>
44→          ) : (
45→            <motion.div
46→              key="list"
47→              className={styles.mobilePanel}
48→              initial={{ x: "-100%" }}
49→              animate={{ x: 0 }}
50→              exit={{ x: "-100%" }}
51→              transition={{ type: "spring", stiffness: 400, damping: 35 }}
52→            >
53→              <ChatSidebar />
54→            </motion.div>
55→          )}
56→        </AnimatePresence>
57→      </div>
58→    </div>
59→  );
60→}
