 1→import { motion } from "motion/react";
 2→import type { Candidate } from "@rearden/types";
 3→import { SkillTag } from "@/components/SkillTag/SkillTag";
 4→import { ScoreBadge } from "@/components/ScoreBadge/ScoreBadge";
 5→import styles from "./CandidateCard.module.scss";
 6→
 7→interface CandidateCardProps {
 8→  candidate: Candidate;
 9→  score?: number;
10→  matchReason?: string;
11→  onClick?: () => void;
12→}
13→
14→export function CandidateCard({
15→  candidate,
16→  score,
17→  matchReason,
18→  onClick,
19→}: CandidateCardProps) {
20→  const displaySkills = candidate.skills.slice(0, 4);
21→
22→  return (
23→    <motion.div
24→      className={styles.card}
25→      whileHover={{ y: -4 }}
26→      whileTap={{ scale: 0.98 }}
27→      transition={{ type: "spring", stiffness: 400, damping: 25 }}
28→      onClick={onClick}
29→      role={onClick ? "button" : undefined}
30→      tabIndex={onClick ? 0 : undefined}
31→    >
32→      <div className={styles.thumbnail}>
33→        {candidate.thumbnailUrl ? (
34→          <img src={candidate.thumbnailUrl} alt={candidate.name} />
35→        ) : (
36→          <div className={styles.placeholder} />
37→        )}
38→        {score !== undefined && (
39→          <div className={styles.scoreBadge}>
40→            <ScoreBadge score={score} />
41→          </div>
42→        )}
43→      </div>
44→
45→      <div className={styles.content}>
46→        <h3 className={styles.name}>{candidate.name}</h3>
47→        <p className={styles.title}>{candidate.title}</p>
48→        <p className={styles.location}>{candidate.location}</p>
49→
50→        <div className={styles.skills}>
51→          {displaySkills.map((skill) => (
52→            <SkillTag key={skill} skill={skill} size="sm" />
53→          ))}
54→        </div>
55→
56→        {matchReason && (
57→          <p className={styles.matchReason}>{matchReason}</p>
58→        )}
59→      </div>
60→    </motion.div>
61→  );
62→}
