  1→import {
  2→  createContext,
  3→  useCallback,
  4→  useContext,
  5→  useEffect,
  6→  useMemo,
  7→  useRef,
  8→  useState,
  9→  type ReactNode,
 10→} from "react";
 11→import type {
 12→  ChatConversation,
 13→  ChatMessage,
 14→  ChatTab,
 15→  WSServerEvent,
 16→} from "@rearden/types";
 17→import { useWebSocket } from "@/hooks/useWebSocket";
 18→
 19→interface TypingIndicator {
 20→  candidateName: string;
 21→  conversationId: string;
 22→}
 23→
 24→interface ChatContextValue {
 25→  conversations: ChatConversation[];
 26→  filteredConversations: ChatConversation[];
 27→  activeConversationId: string | null;
 28→  activeConversation: ChatConversation | null;
 29→  activeMessages: ChatMessage[];
 30→  activeTab: ChatTab;
 31→  searchQuery: string;
 32→  typingIndicators: TypingIndicator[];
 33→  connectionStatus: "connecting" | "connected" | "disconnected";
 34→  setActiveTab: (tab: ChatTab) => void;
 35→  setSearchQuery: (query: string) => void;
 36→  openConversation: (id: string) => void;
 37→  openConversationByCandidate: (candidateId: string) => void;
 38→  closeConversation: () => void;
 39→  sendMessage: (text: string) => void;
 40→  startConversation: (candidateId: string, candidateName: string) => void;
 41→  togglePin: (id: string) => void;
 42→}
 43→
 44→const ChatContext = createContext<ChatContextValue | null>(null);
 45→
 46→export function ChatProvider({ children }: { children: ReactNode }) {
 47→  const [conversations, setConversations] = useState<ChatConversation[]>([]);
 48→  const [messagesCache, setMessagesCache] = useState<Map<string, ChatMessage[]>>(new Map());
 49→  const [activeConversationId, setActiveConversationId] = useState<string | null>(null);
 50→  const [activeTab, setActiveTab] = useState<ChatTab>("all");
 51→  const [searchQuery, setSearchQuery] = useState("");
 52→  const [typingIndicators, setTypingIndicators] = useState<TypingIndicator[]>([]);
 53→  const typingTimers = useRef<Map<string, ReturnType<typeof setTimeout>>>(new Map());
 54→
 55→  const handleWSMessage = useCallback((event: WSServerEvent) => {
 56→    switch (event.type) {
 57→      case "message:new": {
 58→        const { message, conversation } = event;
 59→        setConversations((prev) =>
 60→          prev.map((c) => (c.id === conversation.id ? conversation : c)),
 61→        );
 62→        setMessagesCache((prev) => {
 63→          const next = new Map(prev);
 64→          const msgs = next.get(message.conversationId) ?? [];
 65→          next.set(message.conversationId, [...msgs, message]);
 66→          return next;
 67→        });
 68→        break;
 69→      }
 70→
 71→      case "typing:indicator": {
 72→        const { conversationId, candidateName, isTyping } = event;
 73→        if (isTyping) {
 74→          setTypingIndicators((prev) => {
 75→            if (prev.some((t) => t.conversationId === conversationId)) return prev;
 76→            return [...prev, { candidateName, conversationId }];
 77→          });
 78→          // Auto-clear after 10s
 79→          const existing = typingTimers.current.get(conversationId);
 80→          if (existing) clearTimeout(existing);
 81→          typingTimers.current.set(
 82→            conversationId,
 83→            setTimeout(() => {
 84→              setTypingIndicators((prev) =>
 85→                prev.filter((t) => t.conversationId !== conversationId),
 86→              );
 87→              typingTimers.current.delete(conversationId);
 88→            }, 10000),
 89→          );
 90→        } else {
 91→          setTypingIndicators((prev) =>
 92→            prev.filter((t) => t.conversationId !== conversationId),
 93→          );
 94→          const timer = typingTimers.current.get(conversationId);
 95→          if (timer) {
 96→            clearTimeout(timer);
 97→            typingTimers.current.delete(conversationId);
 98→          }
 99→        }
100→        break;
101→      }
102→
103→      case "conversation:updated": {
104→        setConversations((prev) =>
105→          prev.map((c) => (c.id === event.conversation.id ? event.conversation : c)),
106→        );
107→        break;
108→      }
109→
110→      case "connected":
111→      case "error":
112→        break;
113→    }
114→  }, []);
115→
116→  const { send, status: connectionStatus } = useWebSocket({
117→    onMessage: handleWSMessage,
118→  });
119→
120→  // Fetch conversations on mount
121→  useEffect(() => {
122→    fetch("/api/chat")
123→      .then((r) => r.json())
124→      .then((res) => {
125→        if (res.success) setConversations(res.data);
126→      })
127→      .catch(() => {});
128→  }, []);
129→
130→  const activeConversation =
131→    conversations.find((c) => c.id === activeConversationId) ?? null;
132→
133→  const activeMessages = useMemo(
134→    () => (activeConversationId ? messagesCache.get(activeConversationId) ?? [] : []),
135→    [activeConversationId, messagesCache],
136→  );
137→
138→  // Load messages when opening a conversation
139→  const openConversation = useCallback(
140→    (id: string) => {
141→      setActiveConversationId(id);
142→
143→      // Fetch messages if not cached
144→      if (!messagesCache.has(id)) {
145→        fetch(`/api/chat/${id}/messages`)
146→          .then((r) => r.json())
147→          .then((res) => {
148→            if (res.success) {
149→              setMessagesCache((prev) => new Map(prev).set(id, res.data));
150→            }
151→          })
152→          .catch(() => {});
153→      }
154→
155→      // Mark as read
156→      send({ type: "conversation:read", conversationId: id });
157→      setConversations((prev) =>
158→        prev.map((c) => (c.id === id ? { ...c, unreadCount: 0 } : c)),
159→      );
160→    },
161→    [messagesCache, send],
162→  );
163→
164→  const openConversationByCandidate = useCallback(
165→    (candidateId: string) => {
166→      const conv = conversations.find((c) => c.candidateId === candidateId);
167→      if (conv) openConversation(conv.id);
168→    },
169→    [conversations, openConversation],
170→  );
171→
172→  const closeConversation = useCallback(() => {
173→    setActiveConversationId(null);
174→  }, []);
175→
176→  const sendMessage = useCallback(
177→    (text: string) => {
178→      if (!activeConversationId || !text.trim()) return;
179→
180→      // Optimistic update
181→      const optimisticMsg: ChatMessage = {
182→        id: `opt-${Date.now()}`,
183→        conversationId: activeConversationId,
184→        senderId: "recruiter-1",
185→        senderRole: "recruiter",
186→        text: text.trim(),
187→        createdAt: new Date().toISOString(),
188→      };
189→
190→      setMessagesCache((prev) => {
191→        const next = new Map(prev);
192→        const msgs = next.get(activeConversationId) ?? [];
193→        next.set(activeConversationId, [...msgs, optimisticMsg]);
194→        return next;
195→      });
196→
197→      setConversations((prev) =>
198→        prev.map((c) =>
199→          c.id === activeConversationId
200→            ? { ...c, lastMessage: optimisticMsg, updatedAt: optimisticMsg.createdAt }
201→            : c,
202→        ),
203→      );
204→
205→      send({ type: "message:send", conversationId: activeConversationId, text: text.trim() });
206→    },
207→    [activeConversationId, send],
208→  );
209→
210→  const startConversation = useCallback(
211→    (candidateId: string, candidateName: string) => {
212→      const existing = conversations.find((c) => c.candidateId === candidateId);
213→      if (existing) {
214→        openConversation(existing.id);
215→        return;
216→      }
217→
218→      fetch("/api/chat", {
219→        method: "POST",
220→        headers: { "Content-Type": "application/json" },
221→        body: JSON.stringify({ candidateId, candidateName }),
222→      })
223→        .then((r) => r.json())
224→        .then((res) => {
225→          if (res.success) {
226→            setConversations((prev) => [res.data, ...prev]);
227→            setMessagesCache((prev) => new Map(prev).set(res.data.id, []));
228→            setActiveConversationId(res.data.id);
229→          }
230→        })
231→        .catch(() => {});
232→    },
233→    [conversations, openConversation],
234→  );
235→
236→  const togglePinFn = useCallback(
237→    (id: string) => {
238→      const conv = conversations.find((c) => c.id === id);
239→      if (!conv) return;
240→
241→      const newPinned = !conv.isPinned;
242→      // Optimistic
243→      setConversations((prev) =>
244→        prev.map((c) => (c.id === id ? { ...c, isPinned: newPinned } : c)),
245→      );
246→
247→      fetch(`/api/chat/${id}/pin`, {
248→        method: "PATCH",
249→        headers: { "Content-Type": "application/json" },
250→        body: JSON.stringify({ isPinned: newPinned }),
251→      }).catch(() => {
252→        // Revert
253→        setConversations((prev) =>
254→          prev.map((c) => (c.id === id ? { ...c, isPinned: !newPinned } : c)),
255→        );
256→      });
257→    },
258→    [conversations],
259→  );
260→
261→  const filteredConversations = useMemo(() => {
262→    let result = [...conversations];
263→
264→    // Filter by tab
265→    if (activeTab === "unread") {
266→      result = result.filter((c) => c.unreadCount > 0);
267→    } else if (activeTab === "pinned") {
268→      result = result.filter((c) => c.isPinned);
269→    }
270→
271→    // Filter by search
272→    if (searchQuery.trim()) {
273→      const q = searchQuery.toLowerCase();
274→      result = result.filter(
275→        (c) =>
276→          c.candidateName.toLowerCase().includes(q) ||
277→          c.lastMessage?.text.toLowerCase().includes(q),
278→      );
279→    }
280→
281→    // Sort: pinned first, then by updatedAt
282→    result.sort((a, b) => {
283→      if (a.isPinned !== b.isPinned) return a.isPinned ? -1 : 1;
284→      return new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime();
285→    });
286→
287→    return result;
288→  }, [conversations, activeTab, searchQuery]);
289→
290→  return (
291→    <ChatContext.Provider
292→      value={{
293→        conversations,
