 1→import {
 2→  createContext,
 3→  useCallback,
 4→  useContext,
 5→  useEffect,
 6→  useMemo,
 7→  useState,
 8→  type ReactNode,
 9→} from "react";
10→import {
11→  initialNotifications,
12→  incomingNotifications,
13→  type Notification,
14→} from "@/data/mockNotifications";
15→import { useSound } from "@/hooks/useSound";
16→
17→interface NotificationContextValue {
18→  notifications: Notification[];
19→  unreadCount: number;
20→  dismiss: (id: string) => void;
21→  markRead: (id: string) => void;
22→  markAllRead: () => void;
23→}
24→
25→const NotificationContext = createContext<NotificationContextValue | null>(null);
26→
27→export function NotificationProvider({ children }: { children: ReactNode }) {
28→  const [notifications, setNotifications] = useState<Notification[]>(initialNotifications);
29→  const { playSound } = useSound();
30→
31→  useEffect(() => {
32→    const timers = incomingNotifications.map(({ notification, delayMs }) =>
33→      setTimeout(() => {
34→        setNotifications((prev) => [
35→          { ...notification, timestamp: new Date() },
36→          ...prev,
37→        ]);
38→        playSound("notify");
39→      }, delayMs),
40→    );
41→    return () => timers.forEach(clearTimeout);
42→  }, [playSound]);
43→
44→  const unreadCount = useMemo(
45→    () => notifications.filter((n) => !n.read).length,
46→    [notifications],
47→  );
48→
49→  const dismiss = useCallback((id: string) => {
50→    setNotifications((prev) => prev.filter((n) => n.id !== id));
51→  }, []);
52→
53→  const markRead = useCallback((id: string) => {
54→    setNotifications((prev) =>
55→      prev.map((n) => (n.id === id ? { ...n, read: true } : n)),
56→    );
57→  }, []);
58→
59→  const markAllRead = useCallback(() => {
60→    setNotifications((prev) => prev.map((n) => ({ ...n, read: true })));
61→  }, []);
62→
63→  return (
64→    <NotificationContext.Provider
65→      value={{ notifications, unreadCount, dismiss, markRead, markAllRead }}
66→    >
67→      {children}
68→    </NotificationContext.Provider>
69→  );
70→}
71→
72→export function useNotifications() {
73→  const ctx = useContext(NotificationContext);
74→  if (!ctx)
75→    throw new Error("useNotifications must be used within NotificationProvider");
76→  return ctx;
77→}
