19→export function useSearch() {
20→  const [query, setQuery] = useState("");
21→  const [results, setResults] = useState<SearchResultWithCandidate[]>([]);
22→  const [loading, setLoading] = useState(true);
23→  const [error, setError] = useState<string | null>(null);
24→
25→  const search = useCallback(async (searchQuery: string) => {
26→    setLoading(true);
27→    setError(null);
28→
29→    try {
30→      if (!searchQuery.trim()) {
31→        const response = await apiFetch<{ success: boolean; data: Candidate[] }>("/candidates");
32→        setResults(
33→          response.data.map((candidate, i) => ({
34→            candidateId: candidate.id,
35→            score: 90 - i * 2,
36→            matchReason: "Featured Talent",
37→            candidate,
38→          }))
39→        );
40→      } else {
41→        const response = await apiFetch<{ success: boolean; data: SearchApiResponse }>(
42→          "/search",
43→          {
44→            method: "POST",
45→            body: JSON.stringify({ query: searchQuery }),
46→          }
47→        );
48→        setResults(response.data.results);
49→      }
50→    } catch (e) {
51→      setError(e instanceof Error ? e.message : "Unknown error");
52→    } finally {
53→      setLoading(false);
54→    }
55→  }, []);
56→
57→  useEffect(() => {
58→    const timer = setTimeout(() => {
59→      search(query);
60→    }, 400);
61→    return () => clearTimeout(timer);
62→  }, [query, search]);
