 1→import { useCallback, useEffect, useRef, useState } from "react";
 2→import type { WSClientEvent, WSServerEvent } from "@rearden/types";
 3→
 4→type ConnectionStatus = "connecting" | "connected" | "disconnected";
 5→
 6→interface UseWebSocketOptions {
 7→  onMessage: (event: WSServerEvent) => void;
 8→}
 9→
10→export function useWebSocket({ onMessage }: UseWebSocketOptions) {
11→  const [status, setStatus] = useState<ConnectionStatus>("disconnected");
12→  const wsRef = useRef<WebSocket | null>(null);
13→  const onMessageRef = useRef(onMessage);
14→  onMessageRef.current = onMessage;
15→  const retriesRef = useRef(0);
16→  const timerRef = useRef<ReturnType<typeof setTimeout>>(undefined);
17→
18→  const connect = useCallback(() => {
19→    if (wsRef.current?.readyState === WebSocket.OPEN) return;
20→
21→    const protocol = window.location.protocol === "https:" ? "wss:" : "ws:";
22→    const ws = new WebSocket(`${protocol}//${window.location.host}/ws`);
23→    wsRef.current = ws;
24→    setStatus("connecting");
25→
26→    ws.onopen = () => {
27→      setStatus("connected");
28→      retriesRef.current = 0;
29→    };
30→
31→    ws.onmessage = (e) => {
32→      try {
33→        const data = JSON.parse(e.data) as WSServerEvent;
34→        onMessageRef.current(data);
35→      } catch {
36→        // ignore malformed messages
37→      }
38→    };
39→
40→    ws.onclose = () => {
41→      setStatus("disconnected");
42→      wsRef.current = null;
43→
44→      // Exponential backoff: 1s, 2s, 4s, 8s, max 30s
45→      const delay = Math.min(1000 * 2 ** retriesRef.current, 30000);
46→      retriesRef.current++;
47→      timerRef.current = setTimeout(connect, delay);
48→    };
49→
50→    ws.onerror = () => {
51→      ws.close();
52→    };
53→  }, []);
54→
55→  const send = useCallback((event: WSClientEvent) => {
56→    if (wsRef.current?.readyState === WebSocket.OPEN) {
57→      wsRef.current.send(JSON.stringify(event));
58→    }
59→  }, []);
60→
61→  const reconnect = useCallback(() => {
62→    retriesRef.current = 0;
63→    wsRef.current?.close();
64→    if (timerRef.current) clearTimeout(timerRef.current);
65→    connect();
66→  }, [connect]);
67→
68→  useEffect(() => {
69→    connect();
70→    return () => {
71→      if (timerRef.current) clearTimeout(timerRef.current);
72→      retriesRef.current = Infinity; // prevent reconnect after unmount
73→      wsRef.current?.close();
74→    };
75→  }, [connect]);
76→
77→  return { send, status, reconnect };
78→}
